int main(void) {
    mkfifo(FIFO_PATH, 0600);
    pid_t pid = fork();
    if (pid == 0) {
        /* enfant : lecteur */
        int fd = open(FIFO_PATH, O_RDONLY);
        char buf[32];
        ssize_t n = read(fd, buf, sizeof(buf) - 1);
        buf[n] = '\0';
        printf("Child received: %s\n", buf);
        close(fd);
    } else {
        /* parent : écrivain */
        int fd = open(FIFO_PATH, O_WRONLY);
        const char *msg = "hello ipc";
        write(fd, msg, strlen(msg));
        close(fd);
        wait(NULL);
        unlink(FIFO_PATH);
    }
    return 0;
}

