#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>
#include <sys/wait.h>
#include <string.h>

// ★ Stage 0 — Exemple complet : FIFO nommé inter-processus
// Principe clé : open() sur un FIFO BLOQUE jusqu'à ce que les DEUX extrémités soient ouvertes
// fork() résout ce blocage : enfant et parent ouvrent chacun leur côté

#define FIFO_PATH "/tmp/kf_fifo_02"

int main(void) {
    mkfifo(FIFO_PATH, 0600);     // ★ crée le fichier FIFO
    pid_t pid = fork();          // ★ fork AVANT les open()
    if (pid == 0) {
        /* enfant : lecteur */
        int fd = open(FIFO_PATH, O_RDONLY); // ★ bloque jusqu'à ce que le parent ouvre O_WRONLY
        char buf[32];
        ssize_t n = read(fd, buf, sizeof(buf) - 1);
        buf[n] = '\0';
        printf("Child received: %s\n", buf);
        close(fd);
    } else {
        /* parent : écrivain */
        int fd = open(FIFO_PATH, O_WRONLY); // ★ débloque l'open de l'enfant
        const char *msg = "hello ipc";
        write(fd, msg, strlen(msg));
        close(fd);
        wait(NULL);              // ★ attendre que l'enfant affiche
        unlink(FIFO_PATH);       // ★ nettoyage
    }
    return 0;
}

